VALUES
  ('fire-eq-eng-moex-00363', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法第2章火災預防之規定，下列敘述何者與規定不符？', '["供公眾使用建築物之消防安全設備圖說，應由直轄市、縣（市）消防機關於主管建築機關 許可開工前，審查完成", "供公眾使用建築物，其管理權人應使用附有防焰標示之地毯、窗簾、布幕、展示用廣告板 及其他指定之防焰物品", "非供公眾使用建築物變更為供公眾使用時，主管建築機關應會同消防機關審查其消防安全 設備圖說", "地面樓層達十一層以上建築物、地下建築物或中央主管機關指定之建築物，其管理權有分 屬時，各管理權人應協議製定共同消防防護計畫，並報請消防機關核備"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00364', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法規定，下列有關液化石油氣容器之敘述，何者與規定不同？', '["液化石油氣容器（以下簡稱容器）製造或輸入業者，應向中央主管機關申請型式認可，發 給型式認可證書，始得申請個別認可", "容器應定期檢驗，零售業者應於檢驗期限屆滿後，將容器送經中央主管機關登錄之容器檢 驗機構實施檢驗，使用年限屆滿應汰換之", "容器定期檢驗期限、項目、方式、結果判定、合格標示應載事項與附加方式、不合格容器 之銷毀、容器閥之銷毀及其他相關事項之標準，由中央主管機關公告之", "容器檢驗機構辦理容器檢驗所需費用，由零售業者負擔，其收費項目及費額，由該機構報 請中央主管機關核定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00365', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法施行細則規定，下列敘述何者與規定不同？', '["防火管理人講習訓練時數，初訓不得少於12小時；複訓不得少於6小時", "液化石油氣零售業安全技術人員講習訓練時間不得少於16小時，每次複訓時數不得少於8 小時", "防火管理人初訓合格後，每3年至少應接受複訓一次", "液化石油氣零售業安全技術人員每3年應接受複訓一次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00366', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法施行細則規定，有關公眾使用建築物，下列敘述何者與規定相異？', '["總樓地板面積在500平方公尺以上之餐廳", "總樓地板面積在500平方公尺以上之百貨商場、超級市場及遊藝場等場所", "總樓地板面積在200平方公尺以上之補習班或訓練班", "總樓地板面積在500平方公尺以上，其員工在30人以上之工廠或機關（構）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00367', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防設備師及消防設備士管理辦法規定，下列敘述何者與規定不同？', '["大專以上之在職進修或推廣教育，取得學分或結業證明者，每一學分積分10分，單一課程 以30分為限", "消防設備師及消防設備士，自取得證書日起每 3 年應接受講習一次或取得累計積分達 160 分以上之訓練證明文件", "依專門職業及技術人員考試法規定，經撤銷考試及格資格者，不得請領消防設備師或消防 設備士證書，其已領取者撤銷之", "直轄市、縣（市）之消防設備師或消防設備士達30人以上者，得組織直轄市、縣（市）消 防設備師公會或消防設備士公會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00368', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防安全設備檢修專業機構管理辦法規定，下列敘述何者與規定不同？', '["檢修機構應於年度終結後5個月內，檢具相關書表，報請中央主管機關備查", "檢修機構應於年度開始前2個月至1個月內，檢具相關書表，報請中央主管機關備查", "檢修機構於證書有效期限內，其消防設備師或消防設備士有僱用、解聘、資遣、離職、退 休、死亡或其他異動情事者，應於事實發生之日起1個月內，檢具相關文件，報請中央主 管機關備查", "檢修機構於證書有效期限屆滿前2個月至1個月內，得檢具相關文件，向中央主管機關申 請延展許可，每次延展期限為3年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00369', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防焰性能認證實施要點規定，下列敘述何者與規定不同？', '["申請防焰性能認證，專業機構或直轄市、縣（市）消防機關受理申請之日起1個月內，將 審查結果通知申請人", "申請防焰性能認證，申請案不合程序或有欠缺，其可以補正者，補正期間以1個月為限", "使用防焰標示之業者，每月之使用狀況紀錄至少保存10年，並於每月10日前至專業機構 網站登錄，以供內政部或各級消防機關查核", "防焰性能試驗合格號碼產品於效期內因重新製造或進口販賣前，已重新試驗或屆期前1年 內經消防機關抽購樣試驗合格者，仍應於試驗合格號碼到期前2個月重新申請再登錄，但 得免試驗"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00370', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法，有關六類 物品製造場所或一般處理場所設置、構造、設備之規定，下列敘述何者與規定不同？', '["其外牆或相當於該外牆之設施外側，與公共危險物品及可燃性高壓氣體製造、儲存或處理 場所之安全距離，應在20公尺以上", "四周保留空地寬度應在3公尺以上；儲存量達管制量10倍以上者，四周保留空地寬度應在 5公尺以上", "除本辦法另有規定外，窗戶及出入口應設置1小時以上防火時效之防火門窗", "有積存可燃性蒸氣或可燃性粉塵之虞之建築物，應設置將蒸氣或粉塵有效排至屋簷以上或 室外距地面4公尺以上高處之設備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00371', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法，有關室內 儲槽場所之位置、構造及設備規定，下列敘述何者與規定不同？', '["儲槽專用室之牆壁、柱及地板應為防火構造，樑應以不燃材料建造，外牆有延燒之虞者， 除出入口外，不得設置開口", "儲槽專用室之屋頂應以耐燃材料建造，且不得設置天花板", "儲槽專用室之窗戶及出入口，應設置30分鐘以上防火時效之防火門窗", "儲槽專用室之外牆有延燒之虞者，出入口應設置1小時以上防火時效之常時關閉式防火門"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00372', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法，有關室內 儲槽場所輸送液體六類物品之配管規定，下列敘述何者與規定不同？', '["應為鋼製或金屬製。但鋼製或金屬製配管會造成作業污染者，得設置塑材雙套管", "埋設於地下者，外部應有防蝕功能；接合部分，應有可供檢查之措施。但以熔接接合者， 不在此限", "應經該配管最大常用壓力之1.5倍以上水壓進行耐壓試驗10分鐘，不得洩漏或變形", "以水壓進行耐壓試驗確有困難者，得以該配管最大常用壓力之1倍以上氣壓進行耐壓試驗。 塑材雙套管，其耐壓試驗以內管為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
